const b = $input.first().json.body || $input.first().json;
const instagramUrls = (b.instagram || []).filter(Boolean);
const instagramHandles = instagramUrls.map(u => {
  return String(u).replace(/^https?:\/\/(www\.)?instagram\.com\//, '').replace(/\/$/, '').split('/')[0].toLowerCase();
}).filter(Boolean);
const tiktokProfiles = (b.tiktok || []).map(u => {
  const m = String(u).match(/@([\w.]+)/);
  return m ? '@' + m[1] : u;
}).filter(Boolean);
const facebookUrls = (b.facebook || []).filter(Boolean);
return [{ instagramUrls, instagramHandles, tiktokProfiles, facebookUrls }];

const scan = (obj) => {
  if (!obj || typeof obj !== 'object') return 0;
  const known = ['followersCount','follower_count','ownerFollowersCount','ownerFollowerCount','fans','followers'];
  for (const f of known) { if (obj[f] > 0) return obj[f]; }
  if (obj.edge_followed_by?.count > 0) return obj.edge_followed_by.count;
  for (const k of Object.keys(obj)) {
    const kl = k.toLowerCase();
    if ((kl.includes('follower') || kl === 'fans') && !kl.includes('following') && typeof obj[k] === 'number' && obj[k] > 0) return obj[k];
  }
  return 0;
};

const norm = s => (s || '').toLowerCase().replace(/[^a-z0-9]/g, '');
const igHandles = $('Set Config').first().json.instagramHandles || [];

// Map platform username → closest instagram handle (canonical brand key)
const matchHandle = (u) => {
  const un = norm(u);
  if (!un) return u.toLowerCase();
  const match = igHandles.find(h => {
    const hn = norm(h);
    return hn === un || un.startsWith(hn) || hn.startsWith(un);
  });
  return match || u.toLowerCase();
};

// --- Instagram ---
const igMap = {};
const igDebug = {};
const igProfiles = [];
for (const item of $('IG Scraper').all()) {
  const d = item.json;
  if (Array.isArray(d)) { igProfiles.push(...d); }
  else { igProfiles.push(d); }
}
for (const d of igProfiles) {
  const rawU = (d.username || d.ownerUsername || '').toLowerCase();
  if (!rawU) continue;
  const u = matchHandle(rawU);
  const f = scan(d) || scan(d.owner) || scan(d.user) || 0;
  if (f > 0 || !igMap[u]) igMap[u] = f;
  igDebug[u] = { rawUsername: rawU, foundFollowers: f, followersCount: d.followersCount, postsCount: d.postsCount, isVerified: d.isVerified };
}

// --- TikTok ---
const ttMap = {};
const ttDebug = {};
for (const item of $('TT Scraper').all()) {
  const d = item.json;
  const rawU = (d.authorMeta?.name || d.authorMeta?.nickName || d.authorUniqueId || '').toLowerCase();
  if (!rawU) continue;
  const u = matchHandle(rawU);
  const f = d.authorMeta?.fans || d.authorMeta?.heart || d.authorStats?.followerCount || scan(d.authorMeta) || 0;
  if (f > 0 || !ttMap[u]) ttMap[u] = f;
  ttDebug[u] = { rawUsername: rawU, foundFollowers: f, authorMetaFans: d.authorMeta?.fans, authorMetaKeys: d.authorMeta ? Object.keys(d.authorMeta) : [] };
}

const followers = { ...igMap, ...ttMap };
return [{ followers, debug: { instagram: igDebug, tiktok: ttDebug } }];
